import{_ as e,o as i,c as l,a2 as r}from"./chunks/framework.Cr-Z7ngm.js";const u=JSON.parse('{"title":"香港股票转仓","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"stock-trading/stock-transfer/hk-transfer.md","filePath":"zh-CN/stock-trading/stock-transfer/hk-transfer.md"}'),t={name:"stock-trading/stock-transfer/hk-transfer.md"};function o(n,a,h,s,d,c){return i(),l("div",null,[...a[0]||(a[0]=[r('<h1 id="香港股票转仓" tabindex="-1">香港股票转仓 <a class="header-anchor" href="#香港股票转仓" aria-label="Permalink to &quot;香港股票转仓&quot;">​</a></h1><p>股票转仓（又称转户）是将在一家券商持有的股票转移到另一家券商证券账户的过程，支持转入和转出。仅支持本人同名账户间转仓。</p><h2 id="支持品类" tabindex="-1">支持品类 <a class="header-anchor" href="#支持品类" aria-label="Permalink to &quot;支持品类&quot;">​</a></h2><p>香港市场：股票、ETF<br> 美国市场：股票、ETF</p><h2 id="收费标准" tabindex="-1">收费标准 <a class="header-anchor" href="#收费标准" aria-label="Permalink to &quot;收费标准&quot;">​</a></h2><p>转入：长桥不收费，转出券商可能收费，请与对方券商确认。<br> 转出港股：每支股票 500 港元 / 次<br> 转出美股：每支股票 150 美元 / 次<br> 转出前请确保账户内有足够的手续费。</p><h2 id="处理时间" tabindex="-1">处理时间 <a class="header-anchor" href="#处理时间" aria-label="Permalink to &quot;处理时间&quot;">​</a></h2><p>转入：转仓指示确认后 3-5 个工作日<br> 转出：一般预计 5-10 个工作日（以双方券商实际处理时间为准）</p><hr><h2 id="转入股票" tabindex="-1">转入股票 <a class="header-anchor" href="#转入股票" aria-label="Permalink to &quot;转入股票&quot;">​</a></h2><h3 id="转入券商信息" tabindex="-1">转入券商信息 <a class="header-anchor" href="#转入券商信息" aria-label="Permalink to &quot;转入券商信息&quot;">​</a></h3><p><strong>转入港股：</strong></p><ul><li>接收券商名称：长桥证券（香港）有限公司 Long Bridge HK Limited</li><li>CCASS 代码：B02195</li><li>接收账户：您的长桥证券账户号码</li><li>联系人：交收部</li><li>联系电话：(+852) 3585 8944 / (+852) 3585 8915</li><li>联系邮箱：settlement@longbridge.hk<br><strong>转入美股：</strong></li><li>接收券商名称：Long Bridge HK Limited</li><li>DTC 代码：DTC 0534</li><li>接收账户：您的长桥证券账户号码</li><li>联系人：Settlement Team</li><li>联系电话：(+852) 3585 8944 / (+852) 3585 8915</li><li>联系邮箱：settlement@longbridge.hk</li></ul><p>注意：若转出券商对接收账户格式有限制，可直接填写「U11928885」。</p><h3 id="转入操作流程" tabindex="-1">转入操作流程 <a class="header-anchor" href="#转入操作流程" aria-label="Permalink to &quot;转入操作流程&quot;">​</a></h3><ol><li>长桥 App - 资产 - 存入股票 - 提交转入申请（或资产 - 全部功能 - 转入股票）</li><li>选择转出券商名称，填写转出券商信息，添加需要转出的股票代码及数量</li><li>确认无误后点击「确认提交」，转仓指引会发送至开户注册邮箱</li><li>按邮件指引下载转仓申请表，打印后手写签名，按指引发邮件至转出券商申请转出</li><li>等待双方券商确认后操作转移股票</li></ol><h3 id="转入成本价说明" tabindex="-1">转入成本价说明 <a class="header-anchor" href="#转入成本价说明" aria-label="Permalink to &quot;转入成本价说明&quot;">​</a></h3><p>每股成本价为选填项：</p><ul><li>未填写：成本价按实际转仓成功当日收盘价计算</li><li>已填写：转仓成功后盈亏按填写的成本价计算</li><li>填写后无法修改，如有疑问请联系客服</li></ul><h3 id="各券商转仓指引" tabindex="-1">各券商转仓指引 <a class="header-anchor" href="#各券商转仓指引" aria-label="Permalink to &quot;各券商转仓指引&quot;">​</a></h3><p>各券商转入长桥的详细操作指引请参考 <a href="./各券商转入指引">各券商转入指引</a>，涵盖富途、华盛、老虎、盈透、雪盈、中银国际、华泰国际、恒星、盈立、哈富、荷马、佳兆业、Computershare 共 14 家券商。</p><hr><h2 id="转出股票" tabindex="-1">转出股票 <a class="header-anchor" href="#转出股票" aria-label="Permalink to &quot;转出股票&quot;">​</a></h2><h3 id="长桥转出方信息" tabindex="-1">长桥转出方信息 <a class="header-anchor" href="#长桥转出方信息" aria-label="Permalink to &quot;长桥转出方信息&quot;">​</a></h3><p><strong>转出港股：</strong></p><ul><li>转出券商：长桥证券（香港）有限公司 Long Bridge HK Limited</li><li>CCASS 代码：B02195</li><li>联系人：交收部</li><li>联系电话：(+852) 3585 8944 / (+852) 3585 8915</li><li>联系邮箱：settlement@longbridge.hk<br><strong>转出美股：</strong></li><li>转出券商名称：Long Bridge HK Limited</li><li>DTC 代码：DTC 0534</li><li>联系人：Settlement Team</li><li>联系电话：(+852) 3585 8944 / (+852) 3585 8915</li><li>联系邮箱：settlement@longbridge.hk</li></ul><h3 id="转出操作流程" tabindex="-1">转出操作流程 <a class="header-anchor" href="#转出操作流程" aria-label="Permalink to &quot;转出操作流程&quot;">​</a></h3><ol><li>长桥 App - 资产 - 全部功能 - 转出股票 - 提交转出申请</li><li>填写接收券商信息、账户姓名和接收券商账户号码</li><li>填写股票信息，确认后提交转出申请</li><li>可在转出记录中查看处理进度</li></ol><h3 id="interactive-brokers-盈透-转仓说明" tabindex="-1">Interactive Brokers（盈透）转仓说明 <a class="header-anchor" href="#interactive-brokers-盈透-转仓说明" aria-label="Permalink to &quot;Interactive Brokers（盈透）转仓说明&quot;">​</a></h3><p>经由 Interactive Brokers 转仓时，需在 IB 端提交申请后联系长桥客服提供 IB 方转仓订单编号（Reference Number）。在 IB 填写接收账户时，请填写长桥 H 开头的证券账号，不要填写 UID。</p><hr><h2 id="转仓限制与派息处理" tabindex="-1">转仓限制与派息处理 <a class="header-anchor" href="#转仓限制与派息处理" aria-label="Permalink to &quot;转仓限制与派息处理&quot;">​</a></h2><ul><li>仅支持本人同名账户间转仓</li><li>只有「待提交」状态的申请才能修改，「执行中」状态需重新提交</li><li>取消转仓申请需双方券商同时取消</li><li>持仓股票需结算完成才可提交转出</li><li>转仓过程中如遇股票派息，长桥收到股息后会入账至客户长桥账户<br><a href="https://pub.lbkrs.com/files/202602/rdnfx1shWbkNDAwD/___20260206.pdf" target="_blank" rel="noreferrer">- 如无法在 App 内操作，可通过邮件申请，转仓表格</a></li></ul>',33)])])}const p=e(t,[["render",o]]);export{u as __pageData,p as default};
